In _stratum_treatment_counts (src/fieldtrial/design/policies.py), cap each stratum's allocation by its eligible capacity (markets not forbidden and not fixed controls), floor it by its required markets, and redistribute using eligible capacity:

def _stratum_treatment_counts(self, by_stratum: dict[str, list[str]]) -> dict[str, int]:
    unavailable = set(self.forbidden_treatment_markets).union(self.fixed_control_markets)
    required = set(self.required_treatment_markets)
    ordered = sorted(by_stratum.items())
    capacity = {s: sum(1 for m in ms if m not in unavailable) for s, ms in ordered}
    floor = {s: sum(1 for m in ms if m in required) for s, ms in ordered}
    total = sum(len(ms) for ms in by_stratum.values())
    counts: dict[str, int] = {}
    remaining = self.treatment_count
    for index, (stratum, markets) in enumerate(ordered):
        if index == len(ordered) - 1:
            count = min(remaining, capacity[stratum])
        else:
            count = int(round(self.treatment_count * len(markets) / total))
            count = min(max(count, floor[stratum]), capacity[stratum], remaining)
        counts[stratum] = count
        remaining -= count
    if remaining > 0:
        for stratum, _ in ordered:
            if remaining <= 0:
                break
            spare = capacity[stratum] - counts[stratum]
            if spare <= 0:
                continue
            add = min(spare, remaining)
            counts[stratum] += add
            remaining -= add
    if remaining > 0:
        raise ValueError("stratified policy cannot place treatment_count markets given eligibility constraints")
    return counts

This makes n_feasible_assignments, enumerate(), _sample_stratified, and _enumerate_stratified (which all consume these counts) consistent with per-stratum eligibility, so the repro scenario yields the feasible {A:3, B:1}-style allocations instead of an empty space. Additionally, _draw_policy_assignment (src/fieldtrial/design/candidates.py:401-408) should raise a descriptive error when enumerate() returns an empty list rather than letting rng.integers(0, 0) emit "high <= 0".

