def _dedup_union(rows, attr):
    seen, out = set(), []
    for row in sorted(rows, key=lambda r: r["estimator_name"]):
        for item in getattr(row["metadata"], attr):
            if item not in seen:
                seen.add(item)
                out.append(item)
    return out

